def gcd(a, b):
    if b == 0:
        return a
    else:
        return gcd(b, a % b)

def main():
    n = int(input())
    a = list(map(int, input().split()))
    b = []
    k = 0
    for i in range(1, n):
        if gcd(a[i], a[i-1]) != 1:
            b.append(a[i])
            k += 1
    for i in range(n):
        b.append(a[i])
    print(k)
    print(*b)

if __name__ == "__main__":
    main()
